	// Example:
	"log to logger": {
		"scope": "php",
		"prefix": "lg",
		"body": [
			"\\$logger->log(\"${1:text}\");$0",
		],
		"description": "Log output to log file"
	},
	"log to logger static": {
		"scope": "php",
		"prefix": "Lg",
		"body": [
			"Logger::log(\"${1:text}\");$0",
		],
		"description": "Log output to log file"
	},
	"vd to logger": {
		"scope": "php",
		"prefix": "vd",
		"body": [
			"\\$logger->vd(${1:\\$var});$0",
		],
		"description": "Log output to log file"
	},
	"vd to logger static": {
		"scope": "php",
		"prefix": "Vd",
		"body": [
			"Logger::vd(${1:\\$var});$0",
		],
		"description": "Log output to log file"
	},
	"get logger instance": {
		"scope": "php",
		"prefix": "logger",
		"body": [
			"\\$logger = Logger::getInstance();$0",
		],
		"description": "Log output to console"
	}
